document.addEventListener('DOMContentLoaded', function() { const hamburger = document.querySelector('.hamburger-menu'); const nav = document.querySelector('.header-nav'); if (hamburger && nav) { hamburger.addEventListener('click', () => { hamburger.classList.toggle('active'); nav.classList.toggle('active'); }); } const paginationContainer = document.querySelector('.hero-pagination'); let currentSlide = 0; let autoSlideInterval; let slides; function showSlide(index) { const dots = document.querySelectorAll('.pagination-dot'); if (!slides || !dots || slides.length === 0) { return; } slides.forEach(slide => slide.style.opacity = 0); dots.forEach(dot => dot.classList.remove('active')); slides[index].style.opacity = 1; dots[index].classList.add('active'); currentSlide = index; } function nextSlide() { if (!slides || slides.length === 0) { return; } currentSlide = (currentSlide + 1) % slides.length; showSlide(currentSlide); } const startAutoSlide = () => { clearInterval(autoSlideInterval); autoSlideInterval = setInterval(nextSlide, 5000); }; const resetAutoSlide = () => { clearInterval(autoSlideInterval); startAutoSlide(); }; if (paginationContainer) { paginationContainer.addEventListener('click', (event) => { const clickedDot = event.target.closest('.pagination-dot'); if (clickedDot) { const dotsList = Array.from(paginationContainer.children); const index = dotsList.indexOf(clickedDot); if (index !== -1) { showSlide(index); resetAutoSlide(); } } }); } const handleResize = () => { if (!paginationContainer) { return; } const isMobile = window.innerWidth < 600; slides = document.querySelectorAll(isMobile ? '.slider-item-mobile' : '.slider-item'); if (slides.length === 0) { return; } paginationContainer.innerHTML = ''; slides.forEach((slide) => { const dot = document.createElement('span'); dot.classList.add('pagination-dot'); paginationContainer.appendChild(dot); }); showSlide(currentSlide); startAutoSlide(); }; window.addEventListener('resize', handleResize); handleResize(); });